CustomField.formula:
AND(IsPersonAccount,
OR(MembershipStatus__c = "Aktiv", MembershipStatus__c = 'Begärt utträde'),
OR(AND(
MembershipCategory__c = "Studerande", NOT(ISPICKVAL(SystemPersonSection__c, "Studerandesektionen"))
),
AND(MembershipCategory__c != "Studerande", CurrentEmployer__c != null, CurrentEmployer__r.Section__c != TEXT(SystemPersonSection__c))
)
)
